using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ── DI & Logging ───────────────────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddSingleton<Notebook>();
services.AddSingleton<HttpClient>();

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();

// ── Tools ──────────────────────────────────────────────────────────────────────
var notebook = sp.GetRequiredService<Notebook>();
var httpClient = sp.GetRequiredService<HttpClient>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            WebSearchTool.SearchAsync(httpClient, query),
        "web_search",
        "Searches the web for information on a given query and returns a list of result snippets."),

    AIFunctionFactory.Create(
        ([Description("A concise note summarizing a key finding")] string note) =>
            notebook.AddNote(note),
        "take_note",
        "Saves a research note. Use this to record important findings during research."),

    AIFunctionFactory.Create(
        () => notebook.GetNotes(),
        "get_notes",
        "Retrieves all notes taken so far during the research session."),
};

// ── Agent ──────────────────────────────────────────────────────────────────────
const string instructions = """
    You are a research agent. Your goal is to thoroughly research a topic the user gives you.

    Follow this process:
    1. Break the topic into 2-3 sub-questions.
    2. For each sub-question, call `web_search` to find relevant information.
    3. After each search, call `take_note` to record the most important findings.
    4. Once you have gathered enough information, call `get_notes` to review everything.
    5. Finally, write a well-structured summary with sections and cite your sources.

    Always search at least twice before summarizing. Be factual and concise.
    """;

var agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking.",
    instructions: instructions,
    tools: tools,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>(),
    serviceProvider: sp);

// ── Run ────────────────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

// ── Helpers ────────────────────────────────────────────────────────────────────
static string PromptUser()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.WriteLine("No topic provided. Using default topic.");
        return "Recent advances in quantum computing";
    }
    return input;
}

// ═══════════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════════

/// <summary>Stateful notebook that accumulates research findings.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    public string AddNote(string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count}: {note[..Math.Min(note.Length, 80)]}...");
        return $"Note #{_notes.Count} saved.";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

/// <summary>Web search using the Brave Search API with an HTML-scraping fallback.</summary>
static class WebSearchTool
{
    public static async Task<string> SearchAsync(HttpClient httpClient, string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        // Try Brave Search API first (free tier, 1 req/sec).
        var braveKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
        if (!string.IsNullOrEmpty(braveKey))
        {
            try
            {
                return await BraveSearchAsync(httpClient, query, braveKey);
            }
            catch
            {
                // Fall through to DuckDuckGo fallback.
            }
        }

        // Fallback: DuckDuckGo Instant Answer API (no key required).
        return await DuckDuckGoSearchAsync(httpClient, query);
    }

    private static async Task<string> BraveSearchAsync(
        HttpClient httpClient, string query, string apiKey)
    {
        var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        using var response = await httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());

        var results = new List<string>();
        if (doc.RootElement.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var items))
        {
            foreach (var item in items.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.TryGetProperty("description", out var desc)
                    ? desc.GetString() : "";
                var itemUrl = item.GetProperty("url").GetString();
                results.Add($"- {title}: {snippet} (source: {itemUrl})");
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : "No results found.";
    }

    private static async Task<string> DuckDuckGoSearchAsync(HttpClient httpClient, string query)
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        using var response = await httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var root = doc.RootElement;

        var results = new List<string>();

        // Abstract (main topic summary).
        if (root.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
        {
            var source = root.TryGetProperty("AbstractSource", out var src) ? src.GetString() : "unknown";
            var sourceUrl = root.TryGetProperty("AbstractURL", out var au) ? au.GetString() : "";
            results.Add($"- {abstractText} (source: {source}, {sourceUrl})");
        }

        // Related topics.
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                {
                    var topicUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : "";
                    results.Add($"- {t} (source: {topicUrl})");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : $"Web search returned limited results for \"{query}\". The agent should try rephrasing the query.";
    }
}

