 using Microsoft.Extensions.DependencyInjection;
 using Microsoft.Extensions.Logging;

 // ── Configuration ──────────────────────────────────────────────────────────────
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running this app.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 // ── DI & Logging ───────────────────────────────────────────────────────────────
 var services = new ServiceCollection();
 services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
 services.AddSingleton<Notebook>();
 services.AddSingleton<HttpClient>();

 var openAiClient = new OpenAI.OpenAIClient(apiKey);
 IChatClient innerClient = openAiClient.GetChatClient(modelId).AsIChatClient();
 services.AddChatClient(innerClient);

 var sp = services.BuildServiceProvider();

 // ── Tools ──────────────────────────────────────────────────────────────────────
 var notebook = sp.GetRequiredService<Notebook>();
 var httpClient = sp.GetRequiredService<HttpClient>();

 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(
         ([Description("The search query to look up on the web")] string query) =>
             WebSearchTool.SearchAsync(httpClient, query),
         "web_search",
         "Searches the web for information on a given query and returns a list of result snippets."),

     AIFunctionFactory.Create(
         ([Description("A concise note summarizing a key finding")] string note) =>
             notebook.AddNote(note),
         "take_note",
         "Saves a research note. Use this to record important findings during research."),

     AIFunctionFactory.Create(
         () => notebook.GetNotes(),
         "get_notes",
         "Retrieves all notes taken so far during the research session."),
 };

 // ── Agent ──────────────────────────────────────────────────────────────────────
 const string instructions = """
     You are a research agent. Your goal is to thoroughly research a topic the user gives you.

     Follow this process:
     1. Break the topic into 2-3 sub-questions.
     2. For each sub-question, call `web_search` to find relevant information.
     3. After each search, call `take_note` to record the most important findings.
     4. Once you have gathered enough information, call `get_notes` to review everything.
     5. Finally, write a well-structured summary with sections and cite your sources.

     Always search at least twice before summarizing. Be factual and concise.
     """;

 var agent = new ChatClientAgent(
     sp.GetRequiredService<IChatClient>(),
     name: "ResearchAgent",
     description: "Researches a topic using web search and note-taking.",
     instructions: instructions,
     tools: tools,
     loggerFactory: sp.GetRequiredService<ILoggerFactory>(),
     services: sp);

 // ── Run ────────────────────────────────────────────────────────────────────────
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       AI Research Agent              ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 string topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptUser();

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 var session = await agent.CreateSessionAsync();
 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 4096,
 });

 await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
 {
     Console.Write(update.Text);
 }

