     : PromptUser();

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 var session = await agent.CreateSessionAsync();
 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 4096,
 });

 await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
 {
     Console.Write(update.Text);
 }

 Console.WriteLine("\n\n✅ Research complete.");

 // ── Helpers ────────────────────────────────────────────────────────────────────
 static string PromptUser()
 {
     Console.Write("Enter a research topic: ");
     var input = Console.ReadLine()?.Trim();
     if (string.IsNullOrWhiteSpace(input))
     {
         Console.WriteLine("No topic provided. Using default topic.");
         return "Recent advances in quantum computing";
     }
     return input;
 }

